import { useState, useEffect } from 'react';
import axios from 'axios';
import Refresh from '../RefreshPage/RefreshPage';

function EditTask({ taskData, open, onCloseEditng }){  
    console.log(taskData, open);  
    const [tasks, setTasks] = useState([]);
    // useEffect(async()=>{
    //     console.log("fetching data for id:", taskData.id);
    //     await axios.get(`http://localhost:8001/todos/${taskData.id}`)        
    //     .then((res)=>{
    //         console.log('successfully data fetched for editing: ', res.data.tasks);
    //         setTasks(res.data.tasks);
    //     })
    //     .catch((err)=>{
    //         console.log(err);
    //     })
    // }, [{id}])
    useEffect(()=>{
        console.log("fetching data for id:", taskData);
        setTasks(taskData);
        
    }, [taskData])

    function handleSubmit(e){
        e.preventDefault();
        console.log("inserting data:", tasks);
        axios.post(`http://localhost:8001/todos/${tasks.id}`, tasks)
        .then((res)=> { 
            console.log(res);
            //closeModalEdit(false);
            Refresh();
        })
        .catch((err)=>console.log(err))
    }
    
    if(!open) 
        return null;
    else{
        return(
                <div className='modalBackground'>
                    <div className='modalContainer'>
                        <div className="row">
                            <div className='title'>
                                <h3>Update Task</h3>
                            </div>                    
                            <form onSubmit={handleSubmit} >
                                <div>
                                    <label htmlFor="description">Description</label>
                                    <input value={tasks.description} type='text' name='description' onChange={(e) => setTasks([{...tasks, description: e.target.value}])}/>
                                </div>
                                <div>
                                    <label htmlFor="priority">Priority</label>
                                    <select id='priority' name='priority' value={tasks.priority} onChange={(e) => setTasks([{...tasks, priority: e.target.value}])}>
                                        <option value="">-- Select an option --</option>
                                        <option value="High">High</option>
                                        <option value="Medium">Medium</option>
                                        <option value="Low">Low</option>
                                    </select>
                                </div>
                                <div>
                                    <label htmlFor="status">Status</label>
                                    <select id='status' name='status' value={tasks.status} onChange={(e) => setTasks([{...tasks, status: e.target.value}])}>                                
                                        <option value="">-- Select an option --</option>
                                        <option value="scheduled">Scheduled</option>
                                        <option value="inProgress">In progress</option>
                                        <option value="completed">Completed</option>
                                    </select>
                                </div>
                                <div>
                                    <label htmlFor="target_date">Target Date</label>
                                    <input type='date' name='target_date' value={tasks.target_date} onChange={(e) => setTasks([{...tasks, target_date: e.target.value}])}/>
                                </div>
                                <div>
                                    <label htmlFor="user_id">Asignee</label>
                                    <input type='text' name='user_id' value={tasks.user_id} onChange={(e) => setTasks([{...tasks, user_id: e.target.value}])}/>
                                </div>
                                <div className='footer'>
                                    <button type='submit'>Update</button>
                                    <button onClick={onCloseEditng}>Cancel</button>
                                </div>
                            </form>
                        </div>
                    </div>
                </div>
        )
    }
}

export default EditTask;
